					return Number(cb.dataset.coins) > 0 && cb.dataset.iswelfare != "1";
				});
			}
		} else {
			java.longToast("暂无可购买章节");
		}
	});

	function initSelectAll() {
		allCheckboxes = Array.from(document.querySelectorAll('.item input[type="checkbox"]')).filter(cb => {
			return Number(cb.dataset.coins) > 0 && cb.dataset.iswelfare != "1";
		});
		allCheckboxes.forEach(checkbox => {
			checkbox.removeEventListener('change', handleCheckboxChange);
			checkbox.addEventListener('change', handleCheckboxChange);
		});
		updateSelectAllButton();
		updateTotalDisplay();
	}

	function updateSelectAllButton() {
		if (allCheckboxes.length == 0) {
			selectAllBtn.textContent = '全选';
			selectAllBtn.dataset.state = 'none';
			return;
		}
		const checkedCount = allCheckboxes.filter(cb => cb.checked).length;
		const totalCount = allCheckboxes.length;
		if (checkedCount == totalCount) {
			selectAllBtn.textContent = '取消';
			selectAllBtn.dataset.state = 'all';
		} else if (checkedCount == 0) {
			selectAllBtn.textContent = '全选';
			selectAllBtn.dataset.state = 'none';
		} else {
			selectAllBtn.textContent = '全选';
			selectAllBtn.dataset.state = 'partial';
		}
	}

	function calculateTotal() {
		let total = 0;
		allCheckboxes.forEach(checkbox => {
			if (checkbox.checked) {
				const coins = Number(checkbox.dataset.coins);
				if (!isNaN(coins)) total += coins;
			}
		});
		return total;
	}

	function updateTotalDisplay() {
		if (buyCoinsElement) {
			buyCoinsElement.textContent = calculateTotal();
		}
	}

	function handleCheckboxChange() {
		updateSelectAllButton();
		updateTotalDisplay();
	}

	selectAllBtn.addEventListener('click', function() {
		if (allCheckboxes.length == 0) return;
		const currentState = this.dataset.state;
		const isSelectAll = currentState != 'all';
		allCheckboxes.forEach(checkbox => {
			checkbox.checked = isSelectAll;
		});
		this.textContent = isSelectAll ? '取消' : '全选';
		this.dataset.state = isSelectAll ? 'all' : 'none';
		updateTotalDisplay();
		setTimeout(() => { updateSelectAllButton(); }, 0);
	});

	document.addEventListener('click', function(e) {
		const item = e.target.closest('.item');
		if (item && e.target.tagName != 'INPUT') {
			const checkbox = item.querySelector('input[type="checkbox"]');
			if (checkbox) {
				checkbox.checked = !checkbox.checked;
				const changeEvent = new Event('change', { bubbles: true });
				checkbox.dispatchEvent(changeEvent);
			}
		}
	});

	initSelectAll();
	updateBoughtPercentage();
}, 500);`;

