	let script = `setTimeout(function() {
	let order = 0;
	let base = "https://android.jjwxc.net/comment/getCommentList";
	let currentUrl = \`${currentUrl}\`;
	let versionCode = "${versionCode}";
	let commentTotal = 0;
	let nocommentTotal = 0;
	let isLoading = false;
	let page = 1;
	let hasMore = true;
	var pageTotal = 1;
	let wrongi = 3;

	const modalOverlay = document.getElementById('modalOverlay');
	const modalContent = document.getElementById('modalContent');

	modalOverlay.addEventListener('click', function(event) {
		if (event.target == modalOverlay) closeModal();
	});

	function closeModal() { modalOverlay.style.display = 'none'; }

	function openModal(id, name) {
		modalOverlay.style.display = 'flex';
		document.querySelector(".modalName").textContent = name;
		document.getElementById('viewCommentsBtn').onclick = function() {
			let url = "https://android.jjwxc.net/app.jjwxc/android/reading/comment/getTopTenNovelComment?versionCode=" + versionCode + "&reader_id=" + id + "&useridentity_check=1";
			java.open("rss", url, name + "的评论", "晋江书单");
		};
		document.getElementById('viewBooklistBtn').onclick = function() {
			let url = "https://android.jjwxc.net/app.jjwxc/android/reading/booklist/get?versionCode=" + versionCode + "&reader_id=" + id + "&type=all";
			java.open("sort", url, name + "的书单", "📖晋江书单");
			setTimeout(function() {checkjjsd();}, 1500);
		};
	}

	document.addEventListener('click', function(e) {
		if (e.target.classList.contains('username')) {
			const readerId = e.target.dataset.readerid;
			const username = e.target.textContent;
			openModal(readerId, username);
		}
	});

	loadUrl();
	openTop();

	document.querySelectorAll('.tab-btn').forEach(btn => {
		btn.addEventListener('click', function() {
			let n = this.textContent;
			document.querySelectorAll('.tab-btn').forEach(x => x.classList.remove('active'));
			if (n != "章评") document.querySelector(".sort-dropdown").style.display = "none";
			if (n == "章评") document.querySelector(".sort-dropdown").style.display = "block";
			commentTotal = 0;
			if (/长评/.test(n)) {
				currentUrl = \`https://android.jjwxc.net/comment/getLongCommentList,{"method":"POST","body":"versionCode=${versionCode}&limit=100&offset=0&${this.bDe(r)}"}\`;
			} else if (/加精/.test(n)) {
				currentUrl = \`\${base},{"method":"POST","body":"versionCode=${versionCode}&limit=100&authorLike=1&offset=0&${this.bDe(r)}"}\`;
			} else {
				currentUrl = \`$\{base}?versionCode=${versionCode}&limit=50&offset=0&commentSort=$\{order}&${this.bDe(r)}\`;
			}
			java.toast("加载中……");
			commentTotal = 0;
			nocommentTotal = 0;
			loadUrl();
			openTop();
			this.classList.add('active');
		});
	});
 
	function openTop() {
		let accent = document.querySelector('.accent');
		if (accent) {
			document.querySelectorAll('.accent').forEach((x,i) => {
				x.addEventListener('click', function(e) {
					let name = this.textContent;
					this.textContent = name == "收起" ? "展开" : "收起";
					document.querySelectorAll('.author-announcement:nth-of-type('+(i+1)+')>*:not(.comment-header)').forEach(element => {
						element.style.display = name == "收起" ? 'none' : "block";
						if (element.className == "comment-info") element.style.display = "flex";
					});
				});
			});
		}
	}

	function loadUrl() {
		let JsonData = getJson(currentUrl);
		let html = createCommentHtml(JsonData);
		document.querySelector('.comments-container').innerHTML = html;
		window.scrollTo(0, 0);
		let loader = document.querySelector(".loading-more");
		wrongi--;
		if (loader && wrongi > 0) {
			java.longToast("正在重试倒数第"+wrongi+"次……");
			loadUrl();
			loader.onclick = () => {
				java.longToast("正在重试……");
				loader.textContent = "加载中……";
				loadUrl();
			};
		} else {
			wrongi = 3;
			java.longToast("加载页面完成");
		}
		openReply();
	}

	const sortDropdown = document.querySelector('.sort-dropdown');
	const sortBtn = document.querySelector('.sort-btn');
	sortBtn.addEventListener('click', function(e) {
		e.stopPropagation();
		const content = document.querySelector('.sort-dropdown-content');
		content.style.display = content.style.display == 'block' ? 'none' : 'block';
	});

	document.addEventListener('click', function() {
		document.querySelector('.sort-dropdown-content').style.display = 'none';
	});

	document.querySelector('.sort-dropdown-content').addEventListener('click', function(e) { e.stopPropagation(); });

	document.querySelectorAll('.sort-dropdown-content a').forEach(link => {
		link.addEventListener('click', function(e) {
			e.preventDefault();
			document.querySelectorAll('.sort-dropdown-content i').forEach(b => b.classList.remove('fa-check'));
			this.querySelector("i").className = 'fas fa-check';
			let sort = this.textContent.trim();
			commentTotal = 0;
			if (/倒序/.test(sort)) order = 0;
			else if (/正序/.test(sort)) order = 1;
			else order = 2;
			source.put("commentSort", order);
			currentUrl = currentUrl.replace(/offset=\\d+/, 'offset=0').replace(/commentSort=\\d+/, 'commentSort='+order);
			java.toast("加载中……");
			loadUrl();
			openTop();
			java.longToast("切换至："+sort);
			document.querySelector('.sort-dropdown-content').style.display = 'none';
		});
	});

	function openReply() {
		document.querySelectorAll('.load-more-replies,.close-more-replies').forEach(btn => {
			btn.addEventListener('click', function(e) {
				let className = this.className;
				if (/load-more-replies/.test(className)) {
					const repliesSection = e.target.parentNode;
					let content = this.textContent;
					let totalnum = Number(content.match(/共(\\d+)/)[1]);
					let dataid = this.dataset.id;
					let datanum = Number(this.dataset.num);
					if (datanum < totalnum) {
						let url = \`https://android.jjwxc.net/comment/getReplyList,{"method":"POST","body":"versionCode=${versionCode}&commentId=\${dataid}&offset=\${datanum}&limit=20&isBackend=2&${this.bDe(r)}"}\`;
						this.insertAdjacentHTML('beforebegin', createHtml(getReplyJson(url), "reply", 1));
						this.dataset.num = datanum + 20;
						let synum = Number(content.match(/还剩(\\d+)/)[1]) - 20;
						if (synum > 0) {
							this.textContent = content.replace(/还剩\\d+/, '还剩'+synum);
						} else {
							e.target.nextElementSibling.classList.remove("hide");
							this.classList.add("hide");
						}
					} else {
						document.querySelectorAll('.reply-add').forEach(x => x.classList.remove("hide"));
						e.target.nextElementSibling.classList.remove("hide");
						this.classList.add("hide");
					}
				} else if (/close-more/.test(className)) {
					this.classList.add("hide");
					e.target.previousElementSibling.classList.remove("hide");
					document.querySelectorAll('.reply-add').forEach(x => x.classList.add("hide"));
				}
			});
		});
	}

	${replaceEmoticons.toString()}
	${formatChineseText.toString()}

	function passText(text) {
		let sre = \`${sre}\`;
		let zi = String.raw\`|为营造更好的评论环境|(?:^\\[[^\\]]+?\\]\\s*(?:嗑到了|kswl)\\s*$)\`;
		sre = sre ? sre + zi : zi.replace(/^\\|/, '');
		sre = sre ? new RegExp(sre.replace(/#|＃/g, '|')) : false;
		return sre ? sre.test(text) : false;
	}

	function getJson(url) {
		try {
			let limit = Number(url.match(/limit=(\\d+)/)[1]);
			let data = String(java.ajax(url));
			let JsonData = JSON.parse(data || "{}");
			data = JsonData?.data ?? {};
			let r = {};
			let cTotal = Number(data.commentTotal);
			pageTotal = Math.ceil(cTotal / limit);
			r.commentTotal = cTotal;
			let commentList = [];
			if (data.commentList == undefined) return JsonData?.message ? JsonData.message : false;
			for (i in data.commentList) {
				let x = data.commentList[i];
				let comment = {};
				let passtext = /营养液|地雷|手榴弹|火箭炮|浅水炸弹|霸王票|深水鱼雷|kswl|嗑到了/;
				if ((x.isdel == 22 && passtext.test(x.commentBody)) || passText(x.commentBody)) {
					nocommentTotal++;
					continue;
				}
				let chaptername = ${!chapter ? 1 : "''"} == 1 ? "第"+x.chapterId+"章" : "";
				let vip = x.is_vip_chapter == "1" ? "💸" : "";
				chaptername = "•" + vip + chaptername;
				comment.meta = x.commentMark + "分•" + x.commentDate + "•" + x.ip_pos + (${!chapter ? 1 : "''"} == 1 ? chaptername : "");
				comment.content = x.commentBody.replace(/href=.*?novelDetail.*?novelid":"(\\d+)".*?>/g, function(m, r) {
					href = \`legado://import/addToBookshelf?src=\${encodeURIComponent('http://app-cdn.jjwxc.net/androidapi/novelbasicinfo?novelId='+r)}\`;
					return 'href="' + href + '">';
				});
				comment.username = x.commentAuthor;
				comment.readerid = x.readerid;
				comment.disagreenum = x.disagreenum;
				comment.agreenum = x.agreenum;
				let top = x.bulletinComment == 1 ? "公告" : ((x.is_top == 1 || x.is_reader_top == 1 || x.is_admin_top == 1) ? "置顶" : "");
				if (top) comment.top = top;
				comment.isAuthor = x.isAuthor;
				comment.icon = x.subscriptionicon;
				comment.rate = x.subscriptionrate;
				comment.replyNum = x.replyTotal ?? 0;
				comment.id = x.commentId;
				comment.author_agree = x.author_agree;
				comment.belike = x.beLike;
				comment.cid = x.chapterId;
				comment.vip = x.is_vip_chapter == "1" ? "💸" : "";
				if (comment.replyNum > 0) comment.list = x.replyAll ? getReplyJson(x.replyAll) : [];
				commentList.push(comment);
			}
			commentTotal += commentList.length;
			if (commentList[0]?.top == "公告" && page > 1) commentTotal--;
			document.querySelector(".page").textContent = "已显示" + commentTotal + "条";
			document.querySelector(".nopage").textContent = "屏蔽" + nocommentTotal + "条";
			r.list = commentList;
			return r;
		} catch (e) {
			return false;
		}
	}

	function getReplyJson(data) {
		try {
			if (/^http/.test(data)) {
				data = java.ajax(data);
				data = JSON.parse(data || "{}")?.data ?? [];
			}
			let replyList = [];
			for (i in data) {
				let x = data[i];
				let reply = {};
				if (passText(x.replyBody)) continue;
				reply.meta = x.floor + "楼•" + x.replyDate + "•" + x.ip_pos;
				reply.content = x.replyBody;
				reply.username = x.replyAuthor;
				reply.readerid = x.readerid;
				reply.disagreenum = x.disagreenum;
				reply.agreenum = x.agreenum;
				reply.isAuthor = x.isAuthor;
				reply.icon = x.subscriptionicon;
				reply.rate = x.subscriptionrate;
				reply.author_agree = x.author_agree;
				replyList.push(reply);
			}
			return replyList;
		} catch (e) {
			return [];
		}
	}

	function createCommentHtml(JsonData) {
		if (JsonData && typeof JsonData != "string") {
			document.querySelector(".commentTotal").textContent = "共" + JsonData.commentTotal + "条评论";
			if (page >= 2) html = "";
			html = createHtml(JsonData.list, "comment");
			return html;
		} else {
			java.longToast("错误");
			const loader = document.createElement('div');
			loader.className = 'loading-more';
			loader.style.cssText = \`text-align: center;padding: 10px;color: #666;font-size: 14px;\`;
			loader.textContent = typeof JsonData == "string" ? JsonData : "加载失败，点击重试";
			loader.style.color = '#f00';
			return loader.outerHTML;
		}
	}

	function createHtml(JsonData, t, type) {
		let html = "";
		for (i in JsonData) {
			let x = JsonData[i];
			if (page >= 2 && x.top) continue;
			let replyHtml = "";
			if (x.list && x.list.length > 0) {
				let openReply = "";
				if (x.replyNum > 5) {
					openReply = \`<div class="load-more-replies" data-id="\${x.id}" data-num="5"><i class="fa fa-angle-double-down"></i> 共\${x.replyNum}条回复还剩\${x.replyNum-5}条回复</div><div class="close-more-replies hide"><i class="fa fa-angle-double-up"></i> 收起回复</div>\`;
				}
				replyHtml = \`<div class="replies-section">\${createHtml(x.list, "reply")}\${openReply}</div>\`;
			}
			let user_badges = "";
			let jing_badge = "";
			let author_agree_badge = "";
			
			if (x.belike == 1) jing_badge = \`<div class="like" style="flex:1;text-align:right"><div class="badge" style="background:#FFF8E6;color:#FFA502;display:inline-block;">精</div></div>\`;
			if (x.author_agree == 1) author_agree_badge = \`<div class="like" style="margin-right:1px;display:inline-block;"><div class="badge" style="background:#E9F3EE;color:#6CAB8D;display:inline-block;">作者点赞</div></div>\`;
			if (x.top) user_badges = \`<div class="user-badges"><div class="badge primary">\${x.top}</div><div class="badge accent">展开</div></div>\`;
			else if (x.icon || x.rate) user_badges = \`<div class="user-badges"><div class="badge gold">\${x.rate || "100%"}</div></div>\`;

			let info = "";
			if (x.agreenum >= 0) {
				let actionButtons = "";
				if (!(x.agreenum == 0 && x.disagreenum == 0)) {
					actionButtons = \`<div class="action-btn"><i class="far fa-thumbs-up"></i> \${x.agreenum}</div><div class="action-btn"><i class="far fa-thumbs-down"></i> \${x.disagreenum}</div>\`;
				}
				info = \`<div class="comment-info"><div class="comment-meta">\${x.meta.replace(/•$|•(?=•)/,'')}</div><div class="comment-actions">\${author_agree_badge}\${actionButtons}</div></div>\`;
			}
			
			let usernameHtml = \`<div class="username" data-readerid="\${x.readerid || ''}">\${x.username}</div>\`;
			html += \`<div class="\${t}-item\${type ? ' reply-add' : ''}\${x.top ? ' author-announcement' : ''}"><div class="\${t}-header">\${usernameHtml}\${x.isAuthor == 1 ? '<div class="reply-label">作者</div>' : ''}\${user_badges}\${jing_badge}</div><div class="comment-content">\${formatChineseText(replaceEmoticons(x.content))}</div>\${info}\${replyHtml}</div>\`;
		}
		if (t == "comment" && html == "") html = \`<div style="text-align: center;padding: 10px;color: #666;font-size: 14px;">暂无评论</div>\`;
		return html;
	}

	function checkScrollBottom() {
		if (isLoading || !hasMore) return;
		const lastComment = document.querySelector('.comment-item:last-of-type');
		if (!lastComment) return;
		const windowHeight = window.innerHeight;
		const documentHeight = document.documentElement.scrollHeight;
		const scrollTop = window.scrollY || document.documentElement.scrollTop;
		if (documentHeight - (scrollTop + windowHeight) < 100) loadNextPage();
	}

	function loadNextPage() {
		if (isLoading || !hasMore) return;
		page++;
		if (page > pageTotal) {
			hasMore = false;
			const noMore = document.createElement('div');
			noMore.className = 'no-more';
			noMore.textContent = '没有更多评论了';
			noMore.style.cssText = \`text-align: center;padding: 10px;color: #999;font-size: 14px;\`;
			document.querySelector('.comments-container')?.appendChild(noMore);
			return;
		}
		isLoading = true;
		const loader = document.createElement('div');
		loader.className = 'loading-more';
		loader.textContent = '加载 第' + page + '页 中……';
		loader.style.cssText = \`text-align: center;padding: 10px;color: #666;font-size: 14px;\`;
		const container = document.querySelector('.comments-container') || document.body;
		container.appendChild(loader);
		setTimeout(() => {
			fetchMoreComments()
			.then(() => {
				container.removeChild(loader);
				isLoading = false;
			})
			.catch(() => {
				loader.textContent = '加载失败，点击重试';
				loader.style.color = '#f00';
				loader.onclick = () => {
					container.removeChild(loader);
					isLoading = false;
					page--;
					loadUrl();
				};
			});
		}, 100);
	}

	function fetchMoreComments() {
		return new Promise((resolve) => {
			setTimeout(() => {
				let offset = Number(currentUrl.match(/offset=(\\d+)/)[1]);
				let limit = Number(currentUrl.match(/limit=(\\d+)/)[1]);
				offset = offset + limit;
				currentUrl = currentUrl.replace(/offset=\\d+/, "offset=" + offset);
				var htmlString = createCommentHtml(getJson(currentUrl));
				const container = document.querySelector('.comments-container') || document.body;
				const loader = container.querySelector('.loading-more');
				if (loader) loader.insertAdjacentHTML('beforebegin', htmlString);
				else container.insertAdjacentHTML('beforeend', htmlString);
				openReply();
				resolve();
			}, 1000);
		});
	}

	let scrollTimer;
	window.addEventListener('scroll', function() {
		clearTimeout(scrollTimer);
		scrollTimer = setTimeout(checkScrollBottom, 100);
	});

	const topBtn = document.querySelector('#top');
	topBtn.addEventListener('click', function() { window.scrollTo({ top: 0, behavior: 'smooth' }); });

	const bottomBtn = document.querySelector('#down');
	bottomBtn.addEventListener('click', function() { window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' }); });

}, 200)`;

	java.showBrowser("", html, script, `{expandedCornersRadius:10, heightPercentage:0.72}`);
}

