		var cacheKey = "jj_signin_" + token;
		if (!cache.get(cacheKey)) {
			var timestamp = Math.floor(Date.now() / 1000);
			var sign = encode(timestamp + ":" + token);
			var option = {
				method: "POST",
				body: "versionCode=" + Map("versionCode") + "&sign=" + java.encodeURI(sign)
			};
			var response = java.ajax("https://app.jjwxc.org/androidapi/signin," + JSON.stringify(option));
			var resultData = JSON.parse(response);
			if (resultData && resultData.message) {
				java.toast(resultData.message)
			}
			cache.put(cacheKey, "signed", 43200)
		}
	}
} catch (e) {
	java.toast("签到出错: " + e.message)
}
