function showConsumeHistory() {
	let token = Map("token");
	if (!token) {
		java.longToast("❌ 请先登录账号");
		return;
	}
	try {
		let currentPage = 1;
		let limit = 100;
		let allRecords = [];
		let hasMore = true;
		while (hasMore) {
			let offset = (currentPage - 1) * limit;
			let now = new Date();
			let year = now.getFullYear();
			let month = String(now.getMonth() + 1).padStart(2, '0');
			let dateLine = `${year}${month}`;
			let historyUrl = "https://app.jjwxc.org/androidapi/consumerRecords?versionCode=" + Map("versionCode") + "&token=" + token + "&offset=" + offset + "&limit=" + limit + "&dateLine=" + dateLine;
			java.toast("正在加载第" + currentPage + "页消费记录…");
			let response = java.ajax(historyUrl);
			let data = JSON.parse(response);
			if (data.code == "1046" || !Array.isArray(data) || data.length == 0) {
				hasMore = false;
				java.toast("已加载所有消费记录");
			} else {
				data.forEach(item => {
					let novelName = item.novelName;
					let payTime = item.payTime;
					let orderType = item.ordertype;
					let totalSpend = item.totalSpend;
					let formattedTime = formatTimestamp(payTime);
					allRecords.push({
						novelName: novelName,
						payTime: formattedTime,
						orderType: orderType,
						totalSpend: totalSpend,
						authorName: item.authorName,
						novelId: item.novelId,
						novelSize: item.novelSize
					});
				});
				currentPage++;
			}
		}
		if (allRecords.length > 0) {
			allRecords.sort((a, b) => {
				return b.payTime.localeCompare(a.payTime);
			});
			let totalAmount = 0;
			allRecords.forEach(item => {
				totalAmount += parseInt(item.totalSpend) || 0;
			});
			let now = new Date();
			let year = now.getFullYear();
			let month = String(now.getMonth() + 1).padStart(2, '0');
			let displayRecords = allRecords.slice(0, 80);
			let html = generateConsumeHistoryHTML(displayRecords, year, month, totalAmount, allRecords.length);
			java.showBrowser("", html, null, `{expandedCornersRadius:10,heightPercentage:0.72}`);
		} else {
			java.longToast("本月暂无消费记录");
		}
	} catch (e) {
		java.log("获取消费记录错误: " + e);
		java.longToast("加载失败: " + e.message);
	}
}

function generateConsumeHistoryHTML(records, year, month, totalAmount, totalCount) {
	let displayInfo = '';
	if (totalCount > records.length) {
		displayInfo = `显示前${records.length}条/共${totalCount}条`;
	} else {
		displayInfo = `共${records.length}条`;
	}

	let html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>📜 消费记录</title><style>body{font-family:Arial,sans-serif;margin:0;padding:0;min-height:100vh;background:#f8f9fa}.container{max-width:100%;padding:0;box-sizing:border-box}.header{background:linear-gradient(135deg,#2e9918 0%,#1e7a08 100%);color:white;padding:15px;border-radius:8px 8px 0 0;margin-bottom:0}.h3{margin:0 0 5px 0;text-align:center}.stats{display:flex;justify-content:space-between;align-items: center;font-size:14px;margin-top:10px;height: 24px}.history-table{width:100%;border-collapse:collapse;font-size:12px;background:white;border-radius:0 0 8px 8px;overflow:hidden}.history-table th{background:#f5f5f5;color:#2c3e50;padding:10px 8px;text-align:left;font-weight:bold;border-bottom:2px solid #2e9918}.history-table td{padding:10px 8px;border-bottom:1px solid #e0e0e0;vertical-align:top;line-height:1.4}.history-table tr:nth-child(even){background:#f8f9fa}.history-table tr:hover{background:#e8f5e8}.book-info{display:flex;flex-direction:column;gap:2px}.book-name{font-weight:bold;color:#2c3e50;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.author-name{font-size:11px;color:#666;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.time-col{width:80px;min-width:80px;font-size:11px;color:#555;line-height:1.3;text-align:left}.type-col{width:60px;min-width:60px;text-align:left}.type-text{font-size:11px;font-weight:bold;padding:2px 5px;border-radius:3px;display:inline-block;color:#2c3e50}.amount-col{width:50px;min-width:50px;text-align:left}.amount-value{font-weight:bold;color:#e53935;font-size:13px}.no-data{text-align:center;padding:40px;color:#999;font-style:italic;background:white;border-radius:8px;margin:20px}.month-info{font-size:12px;opacity:0.9}.total-amount{font-weight:bold;font-size:16px}</style></head><body><div class="container"><div class="header"><h3 class="h3">📜 消费记录</h3><div class="stats"><div><span>${year}年${month}月</span><span style="margin-left:10px;">${displayInfo}</span></div><div><span>总消费: <span class="total-amount">${totalAmount}点</span></span></div></div></div>`;

	if (records.length > 0) {
		html += `<table class="history-table"><thead><tr><th>书籍信息</th><th class="time-col">消费时间</th><th class="type-col">消费类型</th><th class="amount-col">金额</th></tr></thead><tbody>`;
		records.forEach((item, index) => {
			let formattedTime = item.payTime.replace(' ', '<br>');
			html += `<tr><td><div class="book-info"><div class="book-name">${item.novelName}</div><div class="author-name">作者: ${item.authorName}</div></div></td><td class="time-col">${formattedTime}</td><td class="type-col"><span class="type-text">${item.orderType}</span></td><td class="amount-col"><span class="amount-value">${item.totalSpend}点</span></td></tr>`;
		});
		html += `</tbody></table>`;
	} else {
		html += `<div class="no-data">暂无消费记录</div>`;
	}
	html += `</div></body></html>`;
	return html;
}

function login() {
	let borderColor = (M("段评边框颜色")?.trim() || "#B2B2B2");
	let textColor = (M("段评数字颜色")?.trim() || "#707070");
	setHeaders(`color=${borderColor},${textColor}`);

	let versionCode = (M("versionCode【一定要让“登录头”里有versionCode的参数‼️】")?.trim() || "489");
	setHeaders(`versionCode=${versionCode}`);
}

function loginToken(token) {
	try {
		token = String(token).replace(/undefined|\s/g, "");
		if (!/\d+_\w{32}/.test(token)) {
			token = Map("token");
			java.longToast("\n❌ 请检查填写的token值，不是正确的格式");
		} else {
			java.toast("已更新token值")
		}
		setHeaders(`token=${token}`)
	} catch (e) {
		java.log(e)
	}
}

function showAuthorNoteManager() {
