		notesListHtml += `<div class="note-item"><div class="note-author">${author}</div><div class="note-content">${notes[author]}</div><button class="delete-btn" data-author="${author}">删除</button></div>`;
		noteCount++;
	}
	if (noteCount == 0) notesListHtml = '<div class="empty-notes">暂无作者备注，请在下方添加</div>';
	let html = `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
	<title>✏️ 作者备注管理</title>
