ruleToc.preUpdateJs:
let novelid = null;
if (book && book.tocUrl) {
	let match = book.tocUrl.match(/novelId=(\d+)/);
	novelid = match ? match[1] : null;
}

let bookName = book ? book.name : '';

let isVip = cache.getFromMemory('jj_isVip_' + novelid);

if (isVip != '1') {
	java.log('免费书籍，跳过购买信息缓存');
} else {
	let token = Map('token');

	if (token && novelid) {
		try {
			let versionCode = Map('versionCode');
			let url = `https://android.jjwxc.net/androidapi/chapterList?novelId=${novelid}&more=0&whole=1&token=${token}&versionCode=${versionCode}`;

			let src = java.ajax(url);
			if (src && src.trim() != '') {
				let data = JSON.parse(src);

				if (data.chapterlist) {
					let buyMap = {};
					let totalVip = 0;
					let boughtVip = 0;

					data.chapterlist.forEach(function(ch) {
						let cid = String(ch.chapterid);
						let isLocked = (ch.islock == '1') || (ch.point == 0);
						buyMap[cid] = isLocked;

						if (ch.isvip) {
							let isWelfare = ch.chapterMessage && ch.chapterMessage.includes('福利');
							if (!isWelfare) {
								totalVip++;
								if (ch.point == 0) {
									boughtVip++;
								}
							}
						}
					});

					cache.putMemory('jj_buy_' + novelid, JSON.stringify(buyMap));

					if (totalVip > 0) {
						let percent = Math.round((boughtVip / totalVip) * 100);
						if (percent > 0) {
							java.longToast(`\n《${bookName}》\n已购买 ${boughtVip}/${totalVip} 章 (${percent}%)`);
						}
					}
					java.log('已缓存VIP书籍购买信息');
				}
			}
		} catch (e) {
			java.log('preUpdateJs错误: ' + e);
		}
	}
}

