ruleContent.nextContentUrl:
@js:
nextpage = java.getString("a#next_url@img@src");
nextpageurl = java.getString("a#next_url@href");
if (nextpage.match(/xyy/) && nextpageurl.includes("javascript")) {
	base64Match = result.match(/var _0x857B3d561b\s*=\s*"([^"]+)"/)[1];
	indexMatch = result.match(/var _0x1a2b3c\s*=\s*\[([^\]]+)\]/)[1];
	if (base64Match && indexMatch) {
		var base64 = base64Match;
		var indexArray = JSON.parse('[' + indexMatch + ']');
		var _keyStr = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=";
		var decoded = "";
		var chr1, chr2, chr3;
		var enc1, enc2, enc3, enc4;
		var i = 0;
		base64 = base64.replace(/[^A-Za-z0-9\+\/\=]/g, "");
		while (i < base64.length) {
			enc1 = _keyStr.indexOf(base64.charAt(i++));
			enc2 = _keyStr.indexOf(base64.charAt(i++));
			enc3 = _keyStr.indexOf(base64.charAt(i++));
			enc4 = _keyStr.indexOf(base64.charAt(i++));
			chr1 = (enc1 << 2) | (enc2 >> 4);
			chr2 = ((enc2 & 15) << 4) | (enc3 >> 2);
			chr3 = ((enc3 & 3) << 6) | enc4;
			decoded = decoded + String.fromCharCode(chr1);
			if (enc3 != 64) {
				decoded = decoded + String.fromCharCode(chr2);
			}
			if (enc4 != 64) {
				decoded = decoded + String.fromCharCode(chr3);
			}
		}
		var url = "";
		for (var i = 0; i < indexArray.length; i++) {
			url += decoded.charAt(indexArray[i]);
		}
		url
	}
} else {
	nextpageurl
}
